/**
 * rs-player タッチ/ポインタジェスチャ（モバイル体験）
 *
 * - ダブルタップ: 左半分で 10 秒戻る / 右半分で 10 秒進む（リップル表示）
 * - 長押し: 押している間だけ 2 倍速（離すと元の速度に復帰）
 * - シングルタップ: 再生 / 一時停止（ダブルタップ確定待ちのため少し遅延）
 *
 * 動画の上に透明なジェスチャ層 `.rsp-gestures` を敷いて処理する。中央再生ボタン・
 * コントロールバー・メニューはこの層より上（後ろのDOM）にあるので従来操作は素通しされる。
 * すべてポインタ種別に依存せず動くので、マウス合成イベントでも検証できる。
 */
/**
 * @param {import('./player.js').Player} player
 * @returns {() => void} 解除関数
 */
export function setupGestures(player: import("./player.js").Player): () => void;
